mapper.select:
select ar.*
from t_remote_data rd
join t_airway_reservation ar
on rd.airway_reservation_id = ar.airway_reservation_id
where (rd.serial_number = #{uasId,jdbcType=VARCHAR}
or rd.registration_id = #{uasId,jdbcType=VARCHAR}
or rd.utm_id = #{uasId,jdbcType=VARCHAR}
or rd.specific_sessoion_id = #{uasId,jdbcType=VARCHAR}
or ar.airway_reservation_id = #{reservationId,jdbcType=VARCHAR})
and #{getLocationTimestamp,jdbcType=TIMESTAMP}
between ar.start_at
and ar.end_at
